SET FOREIGN_KEY_CHECKS=0;
SET NAMES utf8mb4;

-- ============================================================
-- 财务/HR/打样/CRM补充/库存补充 模块种子数据 (Part 5)
-- 生成日期: 2025-05-12
-- 包含: 应收/应付/成本/付款/收款/凭证, 员工/考勤/薪资/培训/培训参与,
